CREATE DEFINER=`root`@`localhost` PROCEDURE `GetBookingsByModelCount`(IN p_year INT, IN p_month INT)
BEGIN
    SELECT m.model_name, COUNT(b.id) as booking_count, SUM(b.ex_showroom) as total_revenue
    FROM bookings b
    JOIN vehicle_variants vv ON b.variant_id = vv.id
    JOIN vehicle_models m ON vv.model_id = m.id
    WHERE (p_year IS NULL OR YEAR(b.created_at) = p_year)
      AND (p_month IS NULL OR MONTH(b.created_at) = p_month)
    GROUP BY m.model_name
    ORDER BY COUNT(b.id) DESC;
END ;;
DELIMITER ;
