CREATE DEFINER=`root`@`localhost` PROCEDURE `GetLeadFunnelCounts`(IN p_year INT, IN p_month INT)
BEGIN
    SELECT l.status, COUNT(l.id)
    FROM leads l
    WHERE (p_year IS NULL OR YEAR(l.created_at) = p_year)
      AND (p_month IS NULL OR MONTH(l.created_at) = p_month)
    GROUP BY l.status;
END ;;
