DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `GetMonthlyBookings`(IN p_year INT)
BEGIN
    SELECT DATE_FORMAT(created_at, '%Y-%m') AS month,
           COUNT(*) AS bookings,
           SUM(total_on_road) AS amt
    FROM bookings
    WHERE status <> 'CANCELLED'
      AND (p_year IS NULL OR YEAR(created_at) = p_year)
    GROUP BY month
    ORDER BY month DESC
    LIMIT 12;
END ;;
DELIMITER ;
